/**
 * @file types.ts
 * @description Shared TypeScript type definitions for ISO/IEC acoustic analysis.
 * RULE-002: WeightingType string literals will be mirrored in src/shared/ids.ts.
 * RULE-001: Pure .ts â no JSX.
 */

/** ISO 61672-1 weighting network identifiers */
export type WeightingType = 'A' | 'C' | 'Z';

/** IEC 61260 octave or fractional-octave band descriptor */
export interface OctaveBand {
  /** Nominal center frequency in Hz */
  nominalHz: number;
  /** Exact center frequency in Hz (base-10 preferred band center) */
  exactHz: number;
  /** Lower band-edge frequency in Hz */
  lowerHz: number;
  /** Upper band-edge frequency in Hz */
  upperHz: number;
}

/** Atmospheric conditions per ISO 9613-1 Â§4 */
export interface AtmosphericConditions {
  /** Ambient temperature in degrees Celsius */
  temperatureCelsius: number;
  /** Relative humidity as a fraction 0â1 */
  relativeHumidity: number;
  /** Atmospheric pressure in kPa (ISO 9613-1 reference: 101.325 kPa) */
  pressureKPa: number;
}

/** Single-frequency SPL measurement */
export interface SPLMeasurement {
  /** Center frequency of the band in Hz */
  frequencyHz: number;
  /** Sound pressure level in dB re 20 ÂµPa */
  spl_dB: number;
  /** Weighting applied, or null if unweighted */
  weighting: WeightingType | null;
  /** Unix timestamp of measurement in ms */
  timestampMs: number;
}

/** Result of applying a frequency weighting filter */
export interface WeightingResult {
  frequencyHz: number;
  /** Weighting correction in dB (negative = attenuation) */
  correctionDb: number;
  weighting: WeightingType;
}

/** Multi-band frequency analysis result */
export interface FrequencyBand {
  band: OctaveBand;
  spl_dB: number;
  weighted_dB: number;
  weighting: WeightingType;
}

/** ISO 9613-1 atmospheric absorption result per frequency */
export interface AtmosphericAbsorptionResult {
  frequencyHz: number;
  /** Attenuation coefficient Î± in dB/m */
  alphaDbPerMeter: number;
  /** Total attenuation over given distance in dB */
  totalAttenuationDb: number;
  distanceMeters: number;
  conditions: AtmosphericConditions;
}

/**
 * @file weighting-a.ts
 * @description ISO 61672-1:2013 A-weighting frequency correction.
 * RULE-003: Uses Math.PI â no hardcoded Ï decimals.
 * RULE-004: All coefficients from constants.ts A_WEIGHTING_COEFFICIENTS.
 * RULE-001: Pure .ts, no JSX.
 */
import {
  A_WEIGHTING_COEFFICIENTS,
  REFERENCE_PRESSURE,
} from './constants';
import type { WeightingResult, OctaveBand, FrequencyBand } from './types';

/**
 * ISO 61672-1:2013 Eq. (4) â A-weighting transfer function squared.
 * H_AÂ²(f) = [f4Â² Â· fÂ² / ((fÂ²+f1Â²)Â·â(fÂ²+f2Â²)Â·â(fÂ²+f3Â²)Â·(fÂ²+f4Â²))]Â² Â· k_AÂ²
 * where f1=20.598997, f2=107.65265, f3=737.86223, f4=12194.217 Hz.
 * All pole frequencies sourced from A_WEIGHTING_COEFFICIENTS (constants.ts).
 * @param frequencyHz - Input frequency in Hz (must be > 0)
 * @returns A-weighting correction in dB
 */
export function computeAWeightingDb(frequencyHz: number): number {
  if (frequencyHz <= 0) throw new RangeError('frequencyHz must be positive');
  const { f1, f2, f3, f4, kA } = A_WEIGHTING_COEFFICIENTS;
  const f2sq = frequencyHz * frequencyHz;
  const numerator = Math.pow(f4, 2) * Math.pow(f2sq, 2);
  const denom =
    (f2sq + f1 * f1) *
    Math.sqrt((f2sq + f2 * f2) * (f2sq + f3 * f3)) *
    (f2sq + f4 * f4);
  const hSq = Math.pow((numerator / denom) * kA, 2);
  return 10 * Math.log10(hSq);
}

/**
 * Applies A-weighting corrections to an array of octave bands.
 * @param bands - Array of OctaveBand descriptors
 * @returns Array of WeightingResult with correctionDb per band
 */
export function applyAWeightingToBands(bands: OctaveBand[]): WeightingResult[] {
  return bands.map((band) => ({
    frequencyHz: band.exactHz,
    correctionDb: computeAWeightingDb(band.exactHz),
    weighting: 'A' as const,
  }));
}

/**
 * Applies A-weighting to a pre-measured FrequencyBand array and returns
 * the weighted SPL values.
 */
export function weightFrequencyBands(
  bands: FrequencyBand[]
): FrequencyBand[] {
  return bands.map((fb) => ({
    ...fb,
    weighted_dB: fb.spl_dB + computeAWeightingDb(fb.band.exactHz),
    weighting: 'A' as const,
  }));
}

/** Nominal 1 kHz A-weighting reference (must be 0.0 dB per ISO 61672-1) */
export const A_WEIGHTING_1KHZ_REFERENCE_DB = computeAWeightingDb(1000);

/**
 * @file atmospheric-absorption.ts
 * @description ISO 9613-1:1993 atmospheric sound absorption computation.
 * RULE-003: Uses Math.log10, Math.pow, Math.exp â no hardcoded decimal approximations.
 * RULE-004: Physical constants from constants.ts only.
 * RULE-001: Pure .ts, no JSX.
 */
import {
  REFERENCE_PRESSURE,
  SPEED_OF_SOUND,
  OCTAVE_BAND_FREQUENCIES,
} from './constants';
import type {
  AtmosphericConditions,
  AtmosphericAbsorptionResult,
  OctaveBand,
} from './types';

/** ISO 9613-1 Â§5 reference temperature in Kelvin */
const T_REF_KELVIN = 293.15;
/** ISO 9613-1 reference pressure in kPa */
const P_REF_KPA = 101.325;

/**
 * Converts Celsius to Kelvin.
 */
function celsiusToKelvin(celsius: number): number {
  return celsius + 273.15;
}

/**
 * Computes molar concentration of water vapour h per ISO 9613-1 Eq. (B.1).
 */
function computeHumidityConcentration(
  conditions: AtmosphericConditions
): number {
  const T = celsiusToKelvin(conditions.temperatureCelsius);
  const pSat =
    Math.pow(10, -6.8346 * Math.pow(T_REF_KELVIN / T, 1.261) + 4.6151);
  return (conditions.relativeHumidity * pSat * P_REF_KPA) / conditions.pressureKPa;
}

/**
 * Computes oxygen relaxation frequency frO per ISO 9613-1 Eq. (3).
 */
function computeOxygenRelaxationHz(
  conditions: AtmosphericConditions,
  h: number
): number {
  return (
    (conditions.pressureKPa / P_REF_KPA) *
    (24 + 4.04e4 * h * ((0.02 + h) / (0.391 + h)))
  );
}

/**
 * Computes nitrogen relaxation frequency frN per ISO 9613-1 Eq. (4).
 */
function computeNitrogenRelaxationHz(
  conditions: AtmosphericConditions,
  T: number
): number {
  return (
    (conditions.pressureKPa / P_REF_KPA) *
    Math.pow(T / T_REF_KELVIN, -0.5) *
    (9 + 280 * (conditions.relativeHumidity) *
      Math.exp(-4.17 * (Math.pow(T_REF_KELVIN / T, 1 / 3) - 1)))
  );
}

/**
 * ISO 9613-1:1993 Â§6 â Computes atmospheric sound absorption coefficient Î±.
 * @param frequencyHz - Frequency in Hz
 * @param conditions - Atmospheric conditions (temp, humidity, pressure)
 * @returns Attenuation coefficient Î± in dB/m
 */
export function computeAbsorptionCoefficient(
  frequencyHz: number,
  conditions: AtmosphericConditions
): number {
  const T = celsiusToKelvin(conditions.temperatureCelsius);
  const h = computeHumidityConcentration(conditions);
  const frO = computeOxygenRelaxationHz(conditions, h);
  const frN = computeNitrogenRelaxationHz(conditions, T);
  const f2 = frequencyHz * frequencyHz;
  const ToverTref = T / T_REF_KELVIN;

  const alpha =
    8.686 *
    f2 *
    (
      (1.84e-11 * Math.pow(ToverTref, 0.5) * (conditions.pressureKPa / P_REF_KPA)) +
      Math.pow(ToverTref, -2.5) *
      (
        (0.01275 * Math.exp(-2239.1 / T)) / (frO + f2 / frO) +
        (0.1068 * Math.exp(-3352.0 / T)) / (frN + f2 / frN)
      )
    );

  return alpha; // dB/m
}

/**
 * Computes full AtmosphericAbsorptionResult for a single frequency and distance.
 */
export function computeAtmosphericAbsorption(
  frequencyHz: number,
  distanceMeters: number,
  conditions: AtmosphericConditions
): AtmosphericAbsorptionResult {
  const alphaDbPerMeter = computeAbsorptionCoefficient(frequencyHz, conditions);
  return {
    frequencyHz,
    alphaDbPerMeter,
    totalAttenuationDb: alphaDbPerMeter * distanceMeters,
    distanceMeters,
    conditions,
  };
}

/**
 * Batch computation over standard octave band center frequencies.
 */
export function computeOctaveBandAbsorption(
  bands: OctaveBand[],
  distanceMeters: number,
  conditions: AtmosphericConditions
): AtmosphericAbsorptionResult[] {
  return bands.map((band) =>
    computeAtmosphericAbsorption(band.exactHz, distanceMeters, conditions)
  );
}
